import React, {type PropsWithChildren} from "react";
import {ResponsiveElement, useSeparator} from "../../factory";
import type {IScrollViewComponent} from "@lmb-it/kitsconcerto-types";

const KitsScrollView = ({children, ref, ...props}: PropsWithChildren<IScrollViewComponent>) => {
    const {cssProps, nativeProps} = useSeparator<any>(props);

    return (
        <ResponsiveElement
            ref={ref}
            as={"ScrollView"}
            cssProps={cssProps}
            nativeProps={nativeProps}
            children={children}
        />
    );
};

export default KitsScrollView;
